VALUES
  ('disabled-e0adf6cd-moex-00098', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '有關行政程序法第159條第2項所規定之行政規則類型，下列何者錯誤？', '["行政機關得透過行政規則，訂定一般性之人事管理規定，以利機關內部 組織、事務順利運作", "為收統一與加速行政作業程序之效，行政機關依法就人民須申請許可事 項制定施行細則，亦屬於行政規則", "行政機關為統一所屬公務員或下級機關之法令解釋，得利用行政規則， 就實務上易生爭議之法令予以核釋", "行政機關訂定裁量基準，以協助下級機關或屬官行使裁量權，為行政規則 30830"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00099', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '公務員同一行為先受懲處處分後，復移送懲戒時，下列何者正確？', '["如懲戒法院為免議之判決確定者，原懲處處分之效力不受影響", "如懲戒法院為不受懲戒判決確定者，原懲處處分失其效力", "如懲戒法院為申誡懲戒處分之判決者，原懲處處分之效力不受影響", "如懲戒法院為撤職懲戒處分之判決者，應一併宣告撤銷原懲處處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00100', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '下列何者非屬一般處分？', '["警察機關命非法之集會遊行解散", "主管機關命某私有水庫之所有人當水庫水位達一定高度時，應即開閘門 洩放", "交通警察以手勢指揮某一道路之駕駛人或行人通行", "主管機關公告某新設道路開放通行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00101', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '機關 A 同意農民甲申請於農地上興建綠能設施，甲再向機關 B 申請同意 備案時，B應該尊重A認定符合農地用地綠能設施，此涉及行政處分下列 何種效力？', '["構成要件效力", "形式存續力", "實質存續力", "確認效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00102', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '有關行政契約之敘述，下列何者正確？', '["行政契約締結之形式，得以口頭或書面的方式為之", "行政契約當事人之一方為人民，若行政機關為防止或除去對公益之重大 危害而終止契約時，基於公益之維護，毋庸補償人民財產上之損失", "行政契約內容侵害第三人權利時，應經第三人書面同意，始生效力", "基於契約自由原則，所有公法上法律關係皆得以行政契約之形式加以規 範，毋須考慮法規之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00103', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '下列何者為行政事實行為？', '["公園開放使用之公告", "地政機關所為土地移轉登記", "函請受領人繳還因撤銷補貼許可所生溢領金額之通知", "文化部函復內政部移民署某甲不符入境許可條件之通知"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00104', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '下列何者非行政罰？', '["甲為證券商之總經理，因違反證券交易法，遭主管機關解除其經理人職務", "乙因違反道路交通管理處罰條例，遭主管機關處以罰鍰", "丙無正當理由，攜帶具殺傷力之器械，因違反社會秩序維護法，遭主管 機關沒入其器械", "丁為學校教師，因體罰學生，違反兒童及少年福利與權益保障法規定， 遭主管機關公布其姓名 30830"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00105', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '關於行政執行聲明異議之敘述，下列何者錯誤？', '["對具行政處分性質之執行命令不服，經依行政執行法之聲明異議程序， 聲明異議人可直接提起撤銷訴訟", "受理機關認為聲明異議無理由者，應予以駁回", "不服中央各院之行政執行而聲明異議，由中央各院自行受理異議並為 決定", "受理機關認為聲明異議有理由者，應即停止執行，並撤銷或更正已為之 執行行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00106', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '關於政府資訊公開法之敘述，下列何者錯誤？', '["係以保障人民知的權利，增進人民對公共事務之瞭解、信賴及監督為 目的", "依該法規定，公開之對象為一般人民", "申請人依該法規定申請行政機關提供行政資訊遭拒絕者，如有不服，僅 得於對實體決定聲明不服時，一併聲明之", "依該法規定申請行政機關提供行政資訊之權利，屬實體權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00107', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '土地所有權人甲於1月3日收到新北市政府工務局所開立「申請建築執照 補件通知單」，通知其應於30日內依建築法規定補件，但甲不服並於3月 3日提起訴願。下列何者正確？', '["該補件通知單之性質為觀念通知", "甲提起之訴願已逾訴願期間，訴願管轄機關應以無理由駁回甲之訴願", "甲不服該補件通知單，應向內政部提起訴願", "該補件通知單具有強制效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL)
